import React from 'react';
import { Link } from 'react-router-dom';

export default function TaskCard({ task, onToggle, onDelete }) {
  return (
    <div className="bg-white rounded border p-4 flex flex-col gap-2">
      <div className="flex justify-between items-start">
        <h3 className="font-semibold text-lg">{task.title}</h3>
        <span className={`text-xs px-2 py-1 rounded ${task.priority === 'High' ? 'bg-red-100 text-red-700' : task.priority === 'Medium' ? 'bg-yellow-100 text-yellow-700' : 'bg-green-100 text-green-700'}`}>{task.priority}</span>
      </div>
      {task.description && <p className="text-sm text-gray-700">{task.description}</p>}
      <div className="text-xs text-gray-500">Due: {task.dueDate ? new Date(task.dueDate).toLocaleDateString() : '—'}</div>
      <div className="flex gap-2 pt-2">
        <button onClick={() => onToggle(task)} className="text-sm px-2 py-1 border rounded">
          Mark {task.status === 'Completed' ? 'Pending' : 'Completed'}
        </button>
        <Link to={`/tasks/${task._id}/edit`} className="text-sm px-2 py-1 border rounded">Edit</Link>
        <button onClick={() => onDelete(task)} className="text-sm px-2 py-1 border rounded text-red-600">Delete</button>
      </div>
    </div>
  );
}
